        [Test]
        public void CheckVerticalClass()
        {
            var verticalSliderComponent = Context.Render<MudSlider<int>>(x => x.Add(p => p.Vertical, true));

            IElement VerticalSlider() => verticalSliderComponent.Find(".mud-slider");
